+codeunit 50100 "Azure Foundry Connector"
+{
+    var
+        AzureFoundrySetup: Record "Azure Foundry Setup";
+        HttpClient: HttpClient;
+        AccessToken: Text;
+        TokenExpiryTime: DateTime;
+
+    procedure Initialize(): Boolean
+    begin
+        if not AzureFoundrySetup.Get() then
+            exit(false);
+
+        if not AzureFoundrySetup.Enabled then
+            exit(false);
+
+        exit(ValidateSetup());
+    end;
+
+    local procedure ValidateSetup(): Boolean
+    begin
+        if (AzureFoundrySetup."Endpoint URL" = '') or
+           (AzureFoundrySetup."Tenant ID" = '') or
+           (AzureFoundrySetup."Client ID" = '') or
+           (AzureFoundrySetup."Client Secret" = '')
+        then
+            exit(false);
+
+        exit(true);
+    end;
+
+    procedure TestConnection(): Boolean
+    var
+        ResponseText: Text;
+    begin
+        if not Initialize() then begin
+            UpdateConnectionStatus(false);
+            exit(false);
+        end;
+
+        if not GetAccessToken() then begin
+            UpdateConnectionStatus(false);
+            exit(false);
+        end;
+
+        if SendTestRequest(ResponseText) then begin
+            UpdateConnectionStatus(true);
+            exit(true);
+        end else begin
+            UpdateConnectionStatus(false);
+            exit(false);
+        end;
+    end;
+
+    procedure GetAccessToken(): Boolean
+    var
+        HttpRequestMessage: HttpRequestMessage;
+        HttpResponseMessage: HttpResponseMessage;
+        HttpContent: HttpContent;
+        HttpHeaders: HttpHeaders;
+        RequestBody: Text;
+        ResponseText: Text;
+        TokenUrl: Text;
+        JToken: JsonToken;
+        JObject: JsonObject;
+        ExpiresIn: Integer;
+    begin
+        // Check if token is still valid
+        if (AccessToken <> '') and (TokenExpiryTime > CurrentDateTime) then
+            exit(true);
+
+        // Build token request
+        TokenUrl := StrSubstNo('https://login.microsoftonline.com/%1/oauth2/v2.0/token', AzureFoundrySetup."Tenant ID");
+
+        RequestBody := StrSubstNo(
+            'grant_type=client_credentials&client_id=%1&client_secret=%2&scope=https://management.azure.com/.default',
+            AzureFoundrySetup."Client ID",
+            AzureFoundrySetup."Client Secret");
+
+        HttpContent.WriteFrom(RequestBody);
+        HttpContent.GetHeaders(HttpHeaders);
+        HttpHeaders.Remove('Content-Type');
+        HttpHeaders.Add('Content-Type', 'application/x-www-form-urlencoded');
+
+        HttpRequestMessage.Method := 'POST';
+        HttpRequestMessage.SetRequestUri(TokenUrl);
+        HttpRequestMessage.Content := HttpContent;
+
+        // Send request
+        if not HttpClient.Send(HttpRequestMessage, HttpResponseMessage) then
+            exit(false);
+
+        if not HttpResponseMessage.IsSuccessStatusCode then
+            exit(false);
+
+        HttpResponseMessage.Content.ReadAs(ResponseText);
+
+        // Parse token response
+        if not JObject.ReadFrom(ResponseText) then
+            exit(false);
+
+        if not JObject.Get('access_token', JToken) then
+            exit(false);
+
+        AccessToken := JToken.AsValue().AsText();
+
+        // Get expiry time
+        if JObject.Get('expires_in', JToken) then begin
+            ExpiresIn := JToken.AsValue().AsInteger();
+            TokenExpiryTime := CurrentDateTime + (ExpiresIn * 1000) - 300000; // Subtract 5 minutes buffer
+        end else
+            TokenExpiryTime := CurrentDateTime + 3600000; // Default 1 hour
+
+        exit(true);
+    end;
+
+    local procedure SendTestRequest(var ResponseText: Text): Boolean
+    var
+        HttpRequestMessage: HttpRequestMessage;
+        HttpResponseMessage: HttpResponseMessage;
+        HttpHeaders: HttpHeaders;
+        TestUrl: Text;
+    begin
+        // Simple test request to list subscriptions
+        TestUrl := StrSubstNo(
+            'https://management.azure.com/subscriptions?api-version=%1',
+            AzureFoundrySetup."API Version");
+
+        HttpRequestMessage.Method := 'GET';
+        HttpRequestMessage.SetRequestUri(TestUrl);
+        HttpRequestMessage.GetHeaders(HttpHeaders);
+        HttpHeaders.Add('Authorization', 'Bearer ' + AccessToken);
+
+        if not HttpClient.Send(HttpRequestMessage, HttpResponseMessage) then
+            exit(false);
+
+        HttpResponseMessage.Content.ReadAs(ResponseText);
+        exit(HttpResponseMessage.IsSuccessStatusCode);
+    end;
+
+    procedure SendGetRequest(ResourcePath: Text; var ResponseText: Text): Boolean
+    begin
+        exit(SendRequest('GET', ResourcePath, '', ResponseText));
+    end;
+
+    procedure SendPostRequest(ResourcePath: Text; RequestBody: Text; var ResponseText: Text): Boolean
+    begin
+        exit(SendRequest('POST', ResourcePath, RequestBody, ResponseText));
+    end;
+
+    procedure SendPutRequest(ResourcePath: Text; RequestBody: Text; var ResponseText: Text): Boolean
+    begin
+        exit(SendRequest('PUT', ResourcePath, RequestBody, ResponseText));
+    end;
+
+    procedure SendDeleteRequest(ResourcePath: Text; var ResponseText: Text): Boolean
+    begin
+        exit(SendRequest('DELETE', ResourcePath, '', ResponseText));
+    end;
+
+    local procedure SendRequest(Method: Text; ResourcePath: Text; RequestBody: Text; var ResponseText: Text): Boolean
+    var
+        HttpRequestMessage: HttpRequestMessage;
+        HttpResponseMessage: HttpResponseMessage;
+        HttpContent: HttpContent;
+        HttpHeaders: HttpHeaders;
+        FullUrl: Text;
+    begin
+        if not Initialize() then
+            exit(false);
+
+        if not GetAccessToken() then
+            exit(false);
+
+        // Build full URL
+        if ResourcePath.StartsWith('http') then
+            FullUrl := ResourcePath
+        else
+            FullUrl := AzureFoundrySetup."Endpoint URL" + ResourcePath;
+
+        // Add API version if not already in URL
+        if not FullUrl.Contains('api-version') then begin
+            if FullUrl.Contains('?') then
+                FullUrl := FullUrl + '&api-version=' + AzureFoundrySetup."API Version"
+            else
+                FullUrl := FullUrl + '?api-version=' + AzureFoundrySetup."API Version";
+        end;
+
+        // Setup request
+        HttpRequestMessage.Method := Method;
+        HttpRequestMessage.SetRequestUri(FullUrl);
+        HttpRequestMessage.GetHeaders(HttpHeaders);
+        HttpHeaders.Add('Authorization', 'Bearer ' + AccessToken);
+
+        // Add subscription key if configured
+        if AzureFoundrySetup."Subscription Key" <> '' then
+            HttpHeaders.Add('Ocp-Apim-Subscription-Key', AzureFoundrySetup."Subscription Key");
+
+        // Add API key if configured
+        if AzureFoundrySetup."API Key" <> '' then
+            HttpHeaders.Add('api-key', AzureFoundrySetup."API Key");
+
+        // Add body for POST/PUT requests
+        if (Method = 'POST') or (Method = 'PUT') then begin
+            if RequestBody <> '' then begin
+                HttpContent.WriteFrom(RequestBody);
+                HttpContent.GetHeaders(HttpHeaders);
+                HttpHeaders.Remove('Content-Type');
+                HttpHeaders.Add('Content-Type', 'application/json');
+                HttpRequestMessage.Content := HttpContent;
+            end;
+        end;
+
+        // Set timeout
+        HttpClient.Timeout := AzureFoundrySetup."Timeout (seconds)" * 1000;
+
+        // Send request
+        if not HttpClient.Send(HttpRequestMessage, HttpResponseMessage) then
+            exit(false);
+
+        HttpResponseMessage.Content.ReadAs(ResponseText);
+        exit(HttpResponseMessage.IsSuccessStatusCode);
+    end;
+
+    procedure InvokeFoundryModel(ModelName: Text; InputData: Text; var ResponseText: Text): Boolean
+    var
+        ResourcePath: Text;
+        RequestBody: Text;
+        JObject: JsonObject;
+    begin
+        // Build request for Foundry model invocation
+        ResourcePath := StrSubstNo(
+            '/resourceGroups/%1/providers/Microsoft.MachineLearningServices/workspaces/%2/models/%3/invoke',
+            AzureFoundrySetup."Resource Group",
+            AzureFoundrySetup."Workspace Name",
+            ModelName);
+
+        JObject.Add('input', InputData);
+        JObject.WriteTo(RequestBody);
+
+        exit(SendPostRequest(ResourcePath, RequestBody, ResponseText));
+    end;
+
+    procedure GetModelInfo(ModelName: Text; var ResponseText: Text): Boolean
+    var
+        ResourcePath: Text;
+    begin
+        ResourcePath := StrSubstNo(
+            '/resourceGroups/%1/providers/Microsoft.MachineLearningServices/workspaces/%2/models/%3',
+            AzureFoundrySetup."Resource Group",
+            AzureFoundrySetup."Workspace Name",
+            ModelName);
+
+        exit(SendGetRequest(ResourcePath, ResponseText));
+    end;
+
+    procedure ListWorkspaceModels(var ResponseText: Text): Boolean
+    var
+        ResourcePath: Text;
+    begin
+        ResourcePath := StrSubstNo(
+            '/resourceGroups/%1/providers/Microsoft.MachineLearningServices/workspaces/%2/models',
+            AzureFoundrySetup."Resource Group",
+            AzureFoundrySetup."Workspace Name");
+
+        exit(SendGetRequest(ResourcePath, ResponseText));
+    end;
+
+    local procedure UpdateConnectionStatus(Success: Boolean)
+    begin
+        if not AzureFoundrySetup.Get() then
+            exit;
+
+        AzureFoundrySetup."Last Connection Test" := CurrentDateTime;
+        if Success then
+            AzureFoundrySetup."Connection Status" := AzureFoundrySetup."Connection Status"::Success
+        else
+            AzureFoundrySetup."Connection Status" := AzureFoundrySetup."Connection Status"::Failed;
+
+        AzureFoundrySetup.Modify(true);
+    end;
+
+    procedure ClearAccessToken()
+    begin
+        Clear(AccessToken);
+        Clear(TokenExpiryTime);
+    end;
+}
